'use client';
import * as React from 'react';
import { addDays } from 'date-fns';
import type { DateRange } from 'react-day-picker';
import { DollarSign, TrendingUp, Archive, Users2, MessageSquare, Send, Eye, MousePointer, Phone, Clock, Calendar, Wallet } from 'lucide-react';
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { useToast } from '@/hooks/use-toast';
import { PageHeader } from '@/components/layout/page-header';
import { PageContent } from '@/components/layout/page-content';
import { PageContainer } from '@/components/layout/page-container';
import { Card, CardContent } from '@/components/ui/card';

import { BillingTab } from '@/components/ui/billing-tab';
import { PerformanceTab } from '@/components/ui/performance-tab';
import { StaffTab } from '@/components/ui/staff-tab';
import { InventoryTab } from '@/components/ui/inventory-tab';
import { CashClosingTab } from '@/components/ui/cash-closing-tab';
import { OrderDetailsDialog } from '@/components/dialogs/reportes-orderdetails-dialog';
import { MovementsDetailsDialog } from '@/components/dialogs/movements-details-dialog';

// Convex Imports
import { useQuery, usePaginatedQuery, useMutation } from 'convex/react';
import { api } from '@/convex/_generated/api';
import { useEstablishments } from '@/hooks/useEstablishments';
import type { Id } from '@/convex/_generated/dataModel';

// TODO - Crear Tabla en Convex para recoger los datos reales de WhatsApp Metrics

export default function ReportesPage() {
    const { toast } = useToast();
    const { activeEstablishment } = useEstablishments();
    const activeId = activeEstablishment?.id;

    const [isInitialized, setIsInitialized] = React.useState(false);
    React.useEffect(() => {
        setIsInitialized(true);
    }, []);

    // Shared Filters
    const [selectedStaffId, setSelectedStaffId] = React.useState<string>('all');
    const [date, setDate] = React.useState<DateRange | undefined>({
        from: addDays(new Date(), -30),
        to: new Date()
    });

    const [reportType, setReportType] = React.useState<string>('accounts');
    
    // Absence Filters
    const [selectedAbsenceType, setSelectedAbsenceType] = React.useState<string>('all');
    const [selectedAbsenceStatus, setSelectedAbsenceStatus] = React.useState<string>('all');

    // Dialog States
    const [selectedOrderId, setSelectedOrderId] = React.useState<any | null>(null);
    const [isDetailsOpen, setIsDetailsOpen] = React.useState(false);
    const [isMovementsOpen, setIsMovementsOpen] = React.useState(false);

    // --- Convex Data Fetching ---
    const rawStaffMembers = useQuery(api.staff.getStaffByEstablishment, activeId ? { establishmentId: activeId } : "skip") || [];
    const rawProducts = useQuery(api.products.getProducts, activeId ? { establishmentId: activeId } : "skip") || [];
    
    // Mapeo para compatibilidad con componentes UI existentes
    const staffMembers = React.useMemo(() => rawStaffMembers.map((s: any) => ({
        ...s,
        id: s._id,
        nombre: `${s.name} ${s.last_name || ''}`.trim(),
        rol: s.role,
        estado: s.status
    })), [rawStaffMembers]);

    const products = React.useMemo(() => rawProducts.map((p: any) => ({
        ...p,
        id: p._id,
        nombre_producto: p.name,
        precio_venta: p.price,
        url_imagen_producto: p.image || null
    })), [rawProducts]);

    const taxes = useQuery(api.products.getTaxes, activeId ? { establishmentId: activeId } : "skip") || [];
    const ingredients = useQuery(api.ingredients.getIngredients, activeId ? { establishmentId: activeId } : "skip") || [];
    const ingredientCategories = useQuery(api.caja.listCategories, activeId ? { establishmentId: activeId } : "skip") || [];
    const absenceRequests = useQuery(api.staff.getAbsenceRequestsByEstablishment, activeId ? { establishmentId: activeId } : "skip") || [];
    const timeReportData = useQuery(api.staff.getTimeLogsByEstablishment, activeId ? { establishmentId: activeId } : "skip") || [];
    const allOrdersQuery = useQuery(api.orders.listOrders, activeId ? { establishmentId: activeId } : "skip") || [];
    const allReservationsQuery = useQuery(api.reservations.getReservations, activeId ? { establishmentId: activeId } : "skip") || [];
    
    // Mutations
    const updateAbsenceRequestMutation = useMutation(api.staff.updateAbsenceRequestStatus);

    // Paginated Orders for Comandas (Best Practices)
    const {
        results: currentOrders,
        status: ordersStatus,
        loadMore: loadMoreOrders
    } = usePaginatedQuery(
        api.orders.getOrdersForComandas,
        activeId ? { establishmentId: activeId as any } : "skip",
        { initialNumItems: 11 }
    );

    const getCategoryName = (categoryId: string) => {
        const cat = ingredientCategories.find((c: any) => c._id === categoryId);
        return cat ? cat.name : 'Desconocido';
    };

    const getTaxName = (taxId: string) => {
        const tax = taxes.find((t: any) => t._id === taxId);
        return tax ? tax.name : 'Desconocido';
    };

    const handleUpdateRequest = async (req: any, newStatus: any) => {
        try {
            await updateAbsenceRequestMutation({
                requestId: req.id,
                status: newStatus,
                reviewed_by: "system" as any // Temporal sys handler
            });
            toast({
                title: `Solicitud ${newStatus === 'approved' ? 'aprobada' : 'rechazada'}`,
                description: `La solicitud de ausencia ha sido actualizada.`
            });
        } catch (error) {
            toast({ variant: 'destructive', title: 'Error', description: 'No se pudo actualizar la solicitud.' });
        }
    };

    // Cash closing state - TODO: Buscar tabla para Consulta o implementar en Convex
    const [realCash, setRealCash] = React.useState<string>("");
    const initialCash = 100.00;
    
    // Cálculos locales temporales basados en órdenes filtradas para la caja
    const todayOrders = allOrdersQuery.filter((o: any) => o.status === 'paid');
    const totalSales = todayOrders.reduce((acc: number, o: any) => acc + (o.total_amount || 0), 0);
    const cashSales = todayOrders.filter((o: any) => o.payment_type === 'cash' || o.payment_method === 'cash').reduce((acc: number, o: any) => acc + (o.total_amount || 0), 0) || (totalSales * 0.4); // Aproximación temporal
    const cardSales = totalSales - cashSales;
    const theoreticalCash = initialCash + cashSales;
    const cashDifference = realCash ? parseFloat(realCash) - theoreticalCash : null;

    const handleViewDetails = (orderId: string) => {
        // Encontrar el _id de la orden desde la query paginada o general
        const order = currentOrders.find(o => o.orderNumber === orderId || o._id === orderId);
        if (order) {
            setSelectedOrderId(order._id);
            setIsDetailsOpen(true);
        } else {
            toast({
                variant: 'destructive',
                title: 'Error',
                description: 'No se encontraron los detalles para esta comanda.'
            });
        }
    }

    // Pagination adapter for BillingTab since it expects totalPages logic
    // We pass our current page results, and handle loadMore
    const [currentPage, setCurrentPage] = React.useState(1);
    const [ordersPerPage] = React.useState(11);
    
    // Simulamos paginación total usando el total de órdenes si es necesario, o usamos el array currentOrders tal cual
    const totalPages = Math.ceil(allOrdersQuery.length / ordersPerPage) || 1;
    const pageNumbers = Array.from({ length: totalPages }, (_, i) => i + 1).slice(Math.max(0, currentPage - 3), Math.min(totalPages, currentPage + 2));
    const [isAnimating, setIsAnimating] = React.useState(false);

    const indexOfLastOrder = currentPage * ordersPerPage;
    const indexOfFirstOrder = indexOfLastOrder - ordersPerPage;
    const paginatedOrders = currentOrders.slice(indexOfFirstOrder, indexOfLastOrder);

    const paginate = (pageNumber: number) => {
        if (pageNumber < 1 || pageNumber > totalPages) return;
        setIsAnimating(true);
        // Si avanzamos más allá de los resultados actuales, cargamos más
        if (pageNumber * ordersPerPage > currentOrders.length && ordersStatus === "CanLoadMore") {
            loadMoreOrders(ordersPerPage);
        }
        setTimeout(() => {
            setCurrentPage(pageNumber);
            setIsAnimating(false);
        }, 300);
    };

    // --- Time Logs Logic ---
    const timeReportDataMapped = React.useMemo(() => {
        const mapped: any[] = [];
        const logsByStaff = timeReportData.reduce((acc: any, log: any) => {
            if (!acc[log.staffId]) acc[log.staffId] = [];
            acc[log.staffId].push(log);
            return acc;
        }, {});

        for (const staffId in logsByStaff) {
            const logs = logsByStaff[staffId].sort((a: any, b: any) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
            
            for (let i = 0; i < logs.length; i++) {
                if (logs[i].action === 'clock_in') {
                    const entrada = logs[i].timestamp;
                    let salida = undefined;
                    let regularHours = 0;
                    
                    if (i + 1 < logs.length && logs[i+1].action === 'clock_out') {
                        salida = logs[i+1].timestamp;
                        const diff = new Date(salida).getTime() - new Date(entrada).getTime();
                        regularHours = Math.max(0, diff / (1000 * 60 * 60));
                        i++; // skip the clock_out
                    } else {
                        // En turno
                        const diff = new Date().getTime() - new Date(entrada).getTime();
                        regularHours = Math.max(0, diff / (1000 * 60 * 60));
                    }
                    
                    mapped.push({
                        log: {
                            id: logs[i].id || `log-${i}`,
                            staffMemberId: staffId,
                            entrada,
                            salida,
                        },
                        regularHours,
                        extraHours: 0,
                    });
                }
            }
        }
        return mapped;
    }, [timeReportData]);

    const filteredTimeReportData = React.useMemo(() => {
        if (!isInitialized) return [];

        const filteredByStaff = timeReportDataMapped.filter((entry: any) =>
            selectedStaffId === 'all' || entry.log.staffMemberId === selectedStaffId
        );

        return filteredByStaff.filter((entry: any) => {
            const logDate = new Date(entry.log.entrada);
            const isAfterFrom = !date?.from || logDate >= date.from;
            const isBeforeTo = !date?.to || logDate <= date.to;
            return isAfterFrom && isBeforeTo;
        });
    }, [selectedStaffId, date, isInitialized, timeReportDataMapped]);

    const staffTotals = React.useMemo(() => {
        const totals: Record<string, { name: string; regular: number; extra: number }> = {};
        for (const staff of staffMembers) {
            totals[staff.id] = { name: staff.nombre, regular: 0, extra: 0 };
        }
        for (const entry of filteredTimeReportData) {
            if (totals[entry.log.staffMemberId]) {
                totals[entry.log.staffMemberId].regular += entry.regularHours;
                totals[entry.log.staffMemberId].extra += entry.extraHours;
            }
        }
        return totals;
    }, [staffMembers, filteredTimeReportData]);


    // --- Absence Requests Logic ---
    const filteredAbsenceRequests = absenceRequests.filter((req: any) => {
        const matchesStaff = selectedStaffId === 'all' || req.staffId === selectedStaffId;
        const matchesType = selectedAbsenceType === 'all' || req.type === selectedAbsenceType;
        const matchesStatus = selectedAbsenceStatus === 'all' || req.status === selectedAbsenceStatus;
        return matchesStaff && matchesType && matchesStatus;
    });

    // --- WhatsApp Metrics Logic ---
    const whatsappMetrics = React.useMemo(() => {
        if (!isInitialized) return { sales: 0, ordersCount: 0, reservationsCount: 0 };

        const filteredOrders = allOrdersQuery.filter((o: any) => {
            const d = new Date(o.created_at || Date.now());
            const inDate = (!date?.from || d >= date.from) && (!date?.to || d <= date.to);
            return inDate && o.origen_whatsapp === true;
        });

        const filteredReservations = allReservationsQuery.filter((r: any) => {
            const resDate = new Date(r.date || r.created_at || Date.now());
            const inDate = (!date?.from || resDate >= date.from) && (!date?.to || resDate <= date.to);
            return inDate && (r.origen_whatsapp === true || r.source === 'whatsapp');
        });

        const sales = filteredOrders.filter((o: any) => o.status === 'paid').reduce((acc: number, o: any) => acc + (o.total_amount || 0), 0);
        
        return { 
            sales, 
            ordersCount: filteredOrders.length, 
            reservationsCount: filteredReservations.length 
        };
    }, [allOrdersQuery, allReservationsQuery, date, isInitialized]);

    if (!isInitialized || !activeId) {
        return <div>Cargando panel de reportes...</div>
    }

    return (
        <PageContainer>
            <PageHeader title="Panel de Reportes & Cierre de Caja" />
            <PageContent>
                <Tabs defaultValue="billing">
                        <TabsList className="mb-4">
                            <TabsTrigger value="billing" icon={DollarSign}>Facturación</TabsTrigger>
                            <TabsTrigger value="performance" icon={TrendingUp}>Ventas</TabsTrigger>
                            <TabsTrigger value="hours" icon={Clock}>Personal</TabsTrigger>
                            <TabsTrigger value="absences" icon={Calendar}>Ausencias</TabsTrigger>
                            <TabsTrigger value="inventory" icon={Archive}>Inventario</TabsTrigger>
                            <TabsTrigger value="whatsapp" icon={MessageSquare}>WhatsApp</TabsTrigger>
                            <TabsTrigger value="cash-closing" icon={Wallet}>Cierre</TabsTrigger>
                        </TabsList>

                    <BillingTab
                        date={date}
                        onDateChange={setDate}
                        selectedStaffId={selectedStaffId}
                        onStaffChange={setSelectedStaffId}
                        reportType={reportType}
                        onReportTypeChange={setReportType}
                        staffMembers={staffMembers}
                        currentOrders={paginatedOrders as any}
                        currentPage={currentPage}
                        totalPages={totalPages}
                        pageNumbers={pageNumbers}
                        isAnimating={isAnimating}
                        onPaginate={paginate}
                        onViewDetails={handleViewDetails}
                    />

                    <PerformanceTab products={products} orders={allOrdersQuery as any} getCategoryName={getCategoryName} />

                    <StaffTab
                        mode="hours"
                        staffMembers={staffMembers}
                        selectedStaffId={selectedStaffId}
                        onStaffChange={setSelectedStaffId}
                        date={date}
                        onDateChange={setDate}
                        timeReportData={filteredTimeReportData}
                        staffTotals={staffTotals}
                        selectedAbsenceType={selectedAbsenceType}
                        onAbsenceTypeChange={setSelectedAbsenceType}
                        selectedAbsenceStatus={selectedAbsenceStatus}
                        onAbsenceStatusChange={setSelectedAbsenceStatus}
                        filteredAbsenceRequests={filteredAbsenceRequests}
                        onUpdateRequest={handleUpdateRequest}
                    />

                    <StaffTab
                        mode="absences"
                        staffMembers={staffMembers}
                        selectedStaffId={selectedStaffId}
                        onStaffChange={setSelectedStaffId}
                        date={date}
                        onDateChange={setDate}
                        timeReportData={filteredTimeReportData}
                        staffTotals={staffTotals}
                        selectedAbsenceType={selectedAbsenceType}
                        onAbsenceTypeChange={setSelectedAbsenceType}
                        selectedAbsenceStatus={selectedAbsenceStatus}
                        onAbsenceStatusChange={setSelectedAbsenceStatus}
                        filteredAbsenceRequests={filteredAbsenceRequests}
                        onUpdateRequest={handleUpdateRequest}
                    />

                    <InventoryTab
                        products={products}
                        taxes={taxes}
                        ingredients={ingredients}
                        ingredientCategories={ingredientCategories}
                        getTaxName={getTaxName}
                    />
                    <CashClosingTab
                        realCash={realCash}
                        onRealCashChange={setRealCash}
                        initialCash={initialCash}
                        totalSales={totalSales}
                        cashSales={cashSales}
                        cardSales={cardSales}
                        theoreticalCash={theoreticalCash}
                        cashDifference={cashDifference}
                        onOpenMovements={() => setIsMovementsOpen(true)}
                    />

                    {/* WhatsApp Metrics Tab */}
                    <TabsContent value="whatsapp" className="space-y-6 pt-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <Card className="border-l-4 border-l-[#25D366]">
                                <CardContent className="p-6">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <p className="text-sm font-medium text-muted-foreground mb-1">Ventas por WhatsApp</p>
                                            <h3 className="text-3xl font-bold">€{whatsappMetrics.sales.toFixed(2)}</h3>
                                        </div>
                                        <div className="p-3 bg-[#25D366]/10 rounded-full">
                                            <DollarSign className="w-6 h-6 text-[#25D366]" />
                                        </div>
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-4">Ingresos generados vía WhatsApp</p>
                                </CardContent>
                            </Card>

                            <Card className="border-l-4 border-l-[#25D366]">
                                <CardContent className="p-6">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <p className="text-sm font-medium text-muted-foreground mb-1">Pedidos Recibidos</p>
                                            <h3 className="text-3xl font-bold">{whatsappMetrics.ordersCount}</h3>
                                        </div>
                                        <div className="p-3 bg-[#25D366]/10 rounded-full">
                                            <MessageSquare className="w-6 h-6 text-[#25D366]" />
                                        </div>
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-4">Total de pedidos desde WhatsApp</p>
                                </CardContent>
                            </Card>

                            <Card className="border-l-4 border-l-[#25D366]">
                                <CardContent className="p-6">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <p className="text-sm font-medium text-muted-foreground mb-1">Reservas Confirmadas</p>
                                            <h3 className="text-3xl font-bold">{whatsappMetrics.reservationsCount}</h3>
                                        </div>
                                        <div className="p-3 bg-[#25D366]/10 rounded-full">
                                            <Calendar className="w-6 h-6 text-[#25D366]" />
                                        </div>
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-4">Mesas reservadas por WhatsApp</p>
                                </CardContent>
                            </Card>
                        </div>
                    </TabsContent>
                </Tabs>
                <OrderDetailsDialog open={isDetailsOpen} onOpenChange={setIsDetailsOpen} orderId={selectedOrderId} />
                <MovementsDetailsDialog open={isMovementsOpen} onOpenChange={setIsMovementsOpen} />
            </PageContent>
        </PageContainer>
    );
}
