import * as React from 'react';
import Image from 'next/image';
import { Card, CardHeader, CardContent, CardDescription, CardFooter } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Progress } from '@/components/ui/progress';
import { TextSM, H4 } from '@/components/ui/typography';
type Product = any;
import type { Order } from '@/types/orders';

// --- TopProductsCard ---
type TopProductsCardProps = {
  products: Product[];
};

export function TopProductsCard({ products }: TopProductsCardProps) {
  const topProducts = React.useMemo(() => {
    // Simulate sales to get top products
    return [...products]
      .sort((a, b) => (b.price ?? b.precio_venta ?? 0) - (a.price ?? a.precio_venta ?? 0))
      .slice(0, 5)
      .map(p => ({
        ...p,
        revenue: (p.price ?? p.precio_venta ?? 0) * (Math.floor(Math.random() * 20) + 10) // Simulated revenue
      }));
  }, [products]);

  return (
    <Card height="full">
      <CardHeader 
        title="Top 5 Productos Más Vendidos"
      >
        <CardDescription>Productos que más ingresos han generado en el período.</CardDescription>
      </CardHeader>
      <CardContent flex>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Producto</TableHead>
              <TableHead align="right">Ingresos</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {topProducts.map(product => {
              const imageUrl = product.image || product.url_imagen_producto;
              const name = product.name || product.nombre_producto || 'Sin nombre';
              return (
              <TableRow key={product._id || product.id}>
                <TableCell className="flex items-center gap-3">
                  {imageUrl ? (
                    <Image 
                      src={imageUrl} 
                      alt={name} 
                      width={32} 
                      height={32} 
                      className="w-8 h-8 rounded-sm object-cover shrink-0" 
                      data-ai-hint="product image" 
                    />
                  ) : (
                    <div className="w-8 h-8 rounded-sm bg-muted flex items-center justify-center text-muted-foreground font-bold text-xs shrink-0">
                      {name.charAt(0)}
                    </div>
                  )}
                  <span className="font-medium truncate">{name}</span>
                </TableCell>
                <TableCell align="right" variant="medium">€{product.revenue.toFixed(2)}</TableCell>
              </TableRow>
            )})}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

// --- PeakHoursCard ---
type PeakHoursCardProps = {
  orders: Order[];
};

export function PeakHoursCard({ orders }: PeakHoursCardProps) {
  const peakHours = React.useMemo(() => {
    // If no orders, return default mock data
    if (!orders || orders.length === 0) {
      return {
        peakRevenueHour: '21:00',
        peakOrdersHour: '14:00',
        peakAvgTicketHour: '22:00'
      };
    }

    const ordersByHour: { [key: string]: { count: number; revenue: number } } = {};

    orders.forEach(order => {
      if (!order.createdAt) return;
      const hour = new Date(order.createdAt).getHours().toString().padStart(2, '0');
      if (!ordersByHour[hour]) {
        ordersByHour[hour] = { count: 0, revenue: 0 };
      }
      ordersByHour[hour].count++;
      ordersByHour[hour].revenue += order.totalAmount || 0;
    });

    let peakRevenueHour = 'N/A';
    let maxRevenue = 0;
    let peakOrdersHour = 'N/A';
    let maxOrders = 0;
    let peakAvgTicketHour = 'N/A';
    let maxAvgTicket = 0;

    for (const hour in ordersByHour) {
      if (ordersByHour[hour].revenue > maxRevenue) {
        maxRevenue = ordersByHour[hour].revenue;
        peakRevenueHour = `${hour}:00`;
      }
      if (ordersByHour[hour].count > maxOrders) {
        maxOrders = ordersByHour[hour].count;
        peakOrdersHour = `${hour}:00`;
      }
      const avgTicket = ordersByHour[hour].revenue / ordersByHour[hour].count;
      if (avgTicket > maxAvgTicket) {
        maxAvgTicket = avgTicket;
        peakAvgTicketHour = `${hour}:00`;
      }
    }
    return { peakRevenueHour, peakOrdersHour, peakAvgTicketHour };
  }, [orders]);

  return (
    <Card>
      <CardHeader title="Eficiencia y Horas Punta" />
      <CardContent gap="md">
        <div className="flex items-center justify-between">
          <TextSM className="text-muted-foreground">Hora de Más Ventas</TextSM>
          <H4>{peakHours.peakRevenueHour}</H4>
        </div>
        <div className="flex items-center justify-between">
          <TextSM className="text-muted-foreground">Hora con Más Comandas</TextSM>
          <H4>{peakHours.peakOrdersHour}</H4>
        </div>
        <div className="flex items-center justify-between">
          <TextSM className="text-muted-foreground">Ticket Medio Máximo</TextSM>
          <H4>{peakHours.peakAvgTicketHour}</H4>
        </div>
      </CardContent>
    </Card>
  );
}


